const errorData = $input.first().json;
const errorDetails = errorData.execution?.error || {}; // علامة ؟ تمنع توقف الكود لو لا يوجد تفاصيل
const lastNode = errorData.execution?.lastNodeExecuted || 'Unknown Node';

// ضبط الوقت وتحديد المنطقة الزمنية (مهم جداً للسيرفرات)
const now = new Date();
const options = { 
    timeZone: 'Africa/Cairo', // تم ضبطه لتوقيت القاهرة
    hour12: false, // نظام 24 ساعة
    year: 'numeric', month: '2-digit', day: '2-digit', 
    hour: '2-digit', minute: '2-digit', second: '2-digit' 
};

// النتيجة: 02/12/2025 22:15:30
const formattedDate = now.toLocaleString('en-GB', options).replace(',', ''); 

return {
  timestamp: formattedDate,
  failed_node: lastNode,
  error_message: errorDetails.message || 'No error message provided',
  stack_trace: errorDetails.stack || 'No stack trace',
  execution_link: errorData.execution?.url, // إضافة مفيدة: رابط مباشر للتنفيذ
  execution_id: errorData.execution?.id
};

