// استخراج مصفوفة الرسائل
const rawMessages = $input.first().json.messages || [];

// تحويل البيانات لشكل بسيط (Mapping)
const cleanHistory = rawMessages.map(msg => {
  return {
    // توحيد المسميات: human بتبقى user، و ai بتبقى assistant (زي OpenAI Standard)
    role: msg.type === 'human' ? 'user' : 'assistant',
    content: msg.data.content,
    // لو عندك وقت متخزن ممكن تضيفه هنا، لو مفيش سيبه
    // timestamp: msg.data.additional_kwargs?.timestamp
  };
});

// إرجاع النتيجة
return {
  json: {
    success: true,
    count: cleanHistory.length,
    data: cleanHistory
  }
};

// Normalize input
const input = $input.all();
const body = input[0].json.body || input[0].json;

return {
  Text: body.message || body.text || '',
  user_email: body.email || '',
  user_phone: body.phone || '',
  user_name: body.name || '',
  channel: body.channel || 'webhook',
  timestamp: new Date().toISOString(),
  message_id: `msg_${Date.now()}`
};

// Parse AI response
const aiResponse = $input.item(0).json.output;
const inputData = $('Normalize Input').item.json;

let parsed;
try {
  const jsonMatch = aiResponse.match(/\{[\s\S]*\}/);
  parsed = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch (e) {
  parsed = {
    intent: 'general_inquiry',
    sentiment: 'neutral',
    urgency: 'medium',
    language: 'en',
    requires_human: false
  };
}

return {
  ...inputData,
  ...parsed,
  intent_category: parsed.intent?.includes('support') || parsed.intent?.includes('complaint') ? 'support' :
                   parsed.intent?.includes('sales') ? 'sales' :
                   parsed.intent?.includes('order') || parsed.intent?.includes('refund') ? 'order' : 'general'
};

// Parse CRM result
const crmResponse = $input.item(0).json.output;
const intentData = $('Parse Intent Result').item.json;

let crmData;
try {
  const jsonMatch = crmResponse.match(/\{[\s\S]*\}/);
  crmData = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch (e) {
  crmData = {
    action: 'simulated',
    status: 'customer',
    total_messages: 1,
    is_new: false
  };
}

return {
  ...intentData,
  crm_action: crmData.action,
  customer_status: crmData.status,
  customer_total_messages: crmData.total_messages,
  customer_tags: crmData.tags,
  is_new_customer: crmData.is_new || false
};

