// Parse orchestrator decision
const orchResponse = $input.item(0).json.output;
const fullData = $('Parse CRM Result').item.json;

let decision;
try {
  const jsonMatch = orchResponse.match(/\{[\s\S]*\}/);
  decision = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch (e) {
  decision = {
    route_decision: 'search_knowledge_base',
    priority_score: 3,
    actions_taken: [],
    next_agent: 'knowledge_base'
  };
}

return {
  ...fullData,
  route_decision: decision.route_decision,
  priority_score: decision.priority_score,
  actions_taken: decision.actions_taken,
  orchestrator_reasoning: decision.reasoning
};

